DROP TABLE IF EXISTS `main_candidatedetails`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `main_candidatedetails` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `requisition_id` int DEFAULT NULL,
  `candidate_firstname` varchar(50) DEFAULT NULL,
  `candidate_lastname` varchar(50) DEFAULT NULL,
  `candidate_name` varchar(100) NOT NULL,
  `emailid` varchar(70) DEFAULT NULL,
  `contact_number` varchar(15) DEFAULT NULL,
  `job_title_id` int DEFAULT NULL,
  `department` int DEFAULT NULL,
  `work_employment_status` int DEFAULT NULL,
  `client_id` int DEFAULT NULL,
  `ctc` int DEFAULT NULL,
  `current_ctc` int DEFAULT NULL,
  `expected_ctc_with_vp` int DEFAULT NULL,
  `joining_bonus` int DEFAULT NULL,
  `client_billing_rate` varchar(255) DEFAULT NULL,
  `work_location` varchar(255) DEFAULT NULL,
  `notice_period` varchar(255) DEFAULT NULL,
  `joining_date` date DEFAULT NULL,
  `comments` text,
  `current_company_name` varchar(255) DEFAULT NULL,
  `profileimg` varchar(100) DEFAULT NULL,
  `cand_resume` varchar(100) DEFAULT NULL COMMENT 'resume file location',
  `file_id` varchar(255) DEFAULT NULL,
  `verify_proof_name` varchar(255) DEFAULT NULL,
  `verify_proof_id` varchar(255) DEFAULT NULL,
  `cand_resume_deletedby` int DEFAULT NULL,
  `qualification` varchar(100) NOT NULL,
  `experience` float DEFAULT NULL,
  `skillset` text,
  `education_summary` text,
  `summary` text COMMENT 'instead of resume',
  `cand_status` enum('Shortlisted','Selected','Rejected','On hold','Disqualified','Scheduled','Not Scheduled','Recruited','Requisition Closed/Completed') NOT NULL,
  `bgv_status` enum('pending','employee complete','verified') CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NOT NULL DEFAULT 'pending',
  `checker_status` enum('pending','verified') NOT NULL DEFAULT 'pending',
  `verify_comments` varchar(255) DEFAULT NULL,
  `checker_comments` varchar(255) DEFAULT NULL,
  `employee_status` enum('initiated','management_approved','management_rejected','management_cancelled','ceo_approved','ceo_rejected','ceo_cancelled','initiated_bgv','employee_submitted','maker_approved','checker_approved','employee_promoted','bgv_verified') CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `is_ceo_approved` tinyint(1) DEFAULT '0' COMMENT '''1-yes,0-no''',
  `is_direct_approval` tinyint(1) NOT NULL DEFAULT '2' COMMENT '1-yes,0-no',
  `terms_approved` tinyint(1) DEFAULT NULL COMMENT '1-yes,0-no',
  `terms_approved_date` date DEFAULT NULL,
  `backgroundchk_status` enum('In process','Completed','Not Applicable','Yet to start','On hold') DEFAULT 'Yet to start',
  `cand_location` varchar(150) DEFAULT NULL,
  `city` int unsigned DEFAULT NULL,
  `state` int unsigned DEFAULT NULL,
  `country` int unsigned DEFAULT NULL,
  `pincode` varchar(15) DEFAULT NULL,
  `source` enum('Vendor','Website','Referal') DEFAULT NULL,
  `source_val` varchar(150) DEFAULT NULL,
  `organization_name` int DEFAULT NULL COMMENT '1.Codeboard Technology Private Limited\n2.Floki Labs',
  `bond_limit` int DEFAULT NULL COMMENT '0.Without Bond\n1.Two years bond\n3.Three years bond',
  `after_six_month_job_title` int DEFAULT NULL,
  `variable_pay_year_choose_amount` varchar(45) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL,
  `vp_without_bond_duration` varchar(255) DEFAULT NULL,
  `policy_status` enum('policy_not_acknowledge','policy_acknowledged') DEFAULT 'policy_not_acknowledge',
  `offer_leter_status` enum('not_generate','generated') NOT NULL DEFAULT 'not_generate',
  `letter_of_intent` enum('sent','not_send') NOT NULL DEFAULT 'not_send',
  `intent_ctc` varchar(100) DEFAULT NULL,
  `createdby` int unsigned DEFAULT NULL,
  `modifiedby` int unsigned DEFAULT NULL,
  `createddate` datetime DEFAULT NULL,
  `modifieddate` datetime DEFAULT NULL,
  `isactive` tinyint unsigned DEFAULT '1',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=206 DEFAULT CHARSET=utf8mb3;
